'use client';

import { useEffect, useState } from 'react';

export function ManageAccountsModal({ isOpen, onClose, assets, onSave, onAddNew, onRemove, onUpdate }) {
  const [activeIndex, setActiveIndex] = useState(null);
  const [suggestionsByIndex, setSuggestionsByIndex] = useState({});
  const [isSearchingByIndex, setIsSearchingByIndex] = useState({});

  useEffect(() => {
    if (!isOpen || activeIndex === null) return;
    const keyword = (assets[activeIndex]?.name || '').trim();
    if (!keyword) {
      setSuggestionsByIndex((prev) => ({ ...prev, [activeIndex]: [] }));
      setIsSearchingByIndex((prev) => ({ ...prev, [activeIndex]: false }));
      return;
    }

    const controller = new AbortController();
    const timer = setTimeout(async () => {
      try {
        setIsSearchingByIndex((prev) => ({ ...prev, [activeIndex]: true }));
        const res = await fetch(`/api/banks/search?q=${encodeURIComponent(keyword)}&limit=8`, {
          signal: controller.signal,
        });
        const json = await res.json();
        const items = Array.isArray(json.items) ? json.items : [];
        setSuggestionsByIndex((prev) => ({ ...prev, [activeIndex]: items }));
      } catch (error) {
        if (error.name !== 'AbortError') {
          setSuggestionsByIndex((prev) => ({ ...prev, [activeIndex]: [] }));
        }
      } finally {
        setIsSearchingByIndex((prev) => ({ ...prev, [activeIndex]: false }));
      }
    }, 220);

    return () => {
      clearTimeout(timer);
      controller.abort();
    };
  }, [isOpen, activeIndex, assets]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 flex items-center justify-center bg-slate-900/40 p-4 backdrop-blur-xs z-50">
      <div className="w-full max-w-2xl overflow-hidden rounded-2xl border border-rose-100 bg-white shadow-xl flex flex-col max-h-[90vh]">
        <div className="flex items-center justify-between border-b border-rose-100 px-6 py-4 shrink-0">
          <h3 className="flex items-center gap-2 text-sm font-bold text-slate-900">
            ✎ 管理活存與負債餘額
          </h3>
          <button onClick={onClose} className="text-slate-400 transition hover:text-slate-600">
            ✕
          </button>
        </div>

        <div className="p-6 overflow-y-auto space-y-4 flex-1">
          <p className="text-xs text-slate-400">
            您可以在此手動輸入或更新各大銀行、信託、借貸 or 信用卡的名稱與目前金額。更新後點選「全部儲存」將即時同步至 Google Sheets。
          </p>

          <div className="space-y-4">
            {assets.map((item, index) => (
              <div key={item.id} className="flex items-center gap-3 rounded-xl border border-slate-200/60 bg-slate-50 p-3.5">
                <div className="w-1/3">
                  <label className="mb-0.5 block text-[10px] font-bold uppercase text-slate-400">分類</label>
                  <select
                    value={item.category}
                    onChange={(e) => onUpdate(index, { ...item, category: e.target.value, isLiability: e.target.value === '負債項目' })}
                    className="w-full rounded-lg border border-slate-200 bg-white p-1.5 text-xs text-slate-800"
                  >
                    <option value="台幣活存">台幣活存</option>
                    <option value="外幣活存">外幣活存</option>
                    <option value="員工持股信託">員工持股信託</option>
                    <option value="負債項目">負債項目</option>
                  </select>
                </div>
                <div className="w-1/3">
                  <label className="mb-0.5 block text-[10px] font-bold uppercase text-slate-400">名稱</label>
                  <div className="relative">
                    <input
                      type="text"
                      value={item.name}
                      onChange={(e) => {
                        onUpdate(index, { ...item, name: e.target.value });
                        setActiveIndex(index);
                      }}
                      onFocus={() => setActiveIndex(index)}
                      onBlur={() => {
                        setTimeout(() => {
                          setActiveIndex((prev) => (prev === index ? null : prev));
                        }, 120);
                      }}
                      placeholder="例如：台新、國泰、玉山"
                      className="w-full rounded-lg border border-slate-200 bg-white p-1.5 text-xs text-slate-800"
                    />
                    {activeIndex === index && ((suggestionsByIndex[index] || []).length > 0 || isSearchingByIndex[index]) && (
                      <div className="absolute z-20 mt-1 max-h-48 w-full overflow-auto rounded-lg border border-slate-200 bg-white shadow-lg">
                        {isSearchingByIndex[index] && (
                          <div className="px-2 py-1.5 text-[11px] text-slate-400">搜尋中...</div>
                        )}
                        {!isSearchingByIndex[index] &&
                          (suggestionsByIndex[index] || []).map((name) => (
                            <button
                              key={name}
                              type="button"
                              onMouseDown={(e) => e.preventDefault()}
                              onClick={() => {
                                onUpdate(index, { ...item, name });
                                setActiveIndex(null);
                              }}
                              className="block w-full px-2 py-1.5 text-left text-[11px] text-slate-700 transition hover:bg-rose-50"
                            >
                              {name}
                            </button>
                          ))}
                      </div>
                    )}
                  </div>
                </div>
                <div className="w-1/4">
                  <label className="mb-0.5 block text-[10px] font-bold uppercase text-slate-400">金額 (TWD)</label>
                  <input
                    type="number"
                    value={item.balance}
                    onChange={(e) => onUpdate(index, { ...item, balance: Number(e.target.value) || 0 })}
                    className="w-full rounded-lg border border-slate-200 bg-white p-1.5 text-right font-mono text-xs text-slate-800"
                  />
                </div>
                <div className="pt-4">
                  <button
                    onClick={() => onRemove(index)}
                    className="rounded-lg p-1.5 text-slate-400 transition hover:text-rose-500"
                    title="移除本項"
                  >
                    ✕
                  </button>
                </div>
              </div>
            ))}
          </div>

          <button
            onClick={onAddNew}
            className="w-full flex items-center justify-center gap-1 rounded-xl border border-dashed border-slate-300 bg-slate-50 py-2 text-xs font-bold text-slate-500 transition hover:bg-slate-100"
          >
            ➕ 新增一個帳戶/負債項目
          </button>
        </div>

        <div className="border-t border-rose-50 bg-slate-50 px-6 py-4 flex gap-3 shrink-0">
          <button
            type="button"
            onClick={onClose}
            className="w-1/2 rounded-lg border border-slate-200 bg-white py-2.5 text-sm font-semibold text-slate-600 transition hover:bg-slate-100"
          >
            關閉
          </button>
          <button
            type="button"
            onClick={onSave}
            className="w-1/2 rounded-lg bg-rose-500 py-2.5 text-sm font-semibold text-white shadow-md shadow-rose-100 transition hover:bg-rose-600"
          >
            全部儲存同步 
          </button>
        </div>
      </div>
    </div>
  );
}

export function CustomDialog({ isOpen, onClose, title, message, buttons = [] }) {
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 flex items-center justify-center bg-slate-900/40 p-4 backdrop-blur-xs z-50">
      <div className="w-full max-w-md overflow-hidden rounded-2xl border border-slate-200 bg-white p-6 shadow-xl">
        <div className="flex items-start gap-3">
          <div className="rounded-xl bg-rose-50 p-2 text-rose-600">
            ℹ️
          </div>
          <div>
            <h3 className="text-sm font-bold text-slate-900">{title}</h3>
            <p className="mt-1.5 whitespace-pre-line text-xs leading-relaxed text-slate-500" style={{ wordBreak: 'break-all' }}>
              {message}
            </p>
          </div>
        </div>
        <div className="flex justify-end gap-3 pt-4">
          {buttons.map((btn, idx) => (
            <button
              key={idx}
              onClick={btn.onClick}
              className={`rounded-xl px-4 py-2 text-xs font-bold transition ${
                btn.isPrimary
                  ? 'bg-rose-500 text-white shadow-sm shadow-rose-100 hover:bg-rose-600'
                  : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
              }`}
            >
              {btn.label}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';

export function ManageAccountsModal({ isOpen, onClose, assets, onSave, onAddNew, onRemove, onUpdate }) {
  const [activeIndex, setActiveIndex] = useState(null);
  const [suggestionsByIndex, setSuggestionsByIndex] = useState({});
  const [isSearchingByIndex, setIsSearchingByIndex] = useState({});
  const [highlightedByIndex, setHighlightedByIndex] = useState({});

  const pickSuggestion = (index, item) => {
    onUpdate(index, { ...assets[index], name: item });
    setActiveIndex(null);
    setHighlightedByIndex((prev) => ({ ...prev, [index]: -1 }));
  };

  const handleNameKeyDown = (event, index) => {
    const list = suggestionsByIndex[index] || [];
    if (list.length === 0) return;

    if (event.key === 'ArrowDown') {
      event.preventDefault();
      setActiveIndex(index);
      setHighlightedByIndex((prev) => ({
        ...prev,
        [index]: ((prev[index] ?? -1) + 1) % list.length,
      }));
      return;
    }

    if (event.key === 'ArrowUp') {
      event.preventDefault();
      setActiveIndex(index);
      setHighlightedByIndex((prev) => {
        const current = prev[index] ?? -1;
        return {
          ...prev,
          [index]: current <= 0 ? list.length - 1 : current - 1,
        };
      });
      return;
    }

    if (event.key === 'Enter' && activeIndex === index) {
      const highlighted = highlightedByIndex[index] ?? -1;
      if (highlighted >= 0 && highlighted < list.length) {
        event.preventDefault();
        pickSuggestion(index, list[highlighted]);
      }
      return;
    }

    if (event.key === 'Escape') {
      event.preventDefault();
      setActiveIndex(null);
      setHighlightedByIndex((prev) => ({ ...prev, [index]: -1 }));
    }
  };

  useEffect(() => {
    if (!isOpen || activeIndex === null) return;
    const keyword = (assets[activeIndex]?.name || '').trim();
    if (!keyword) {
      setSuggestionsByIndex((prev) => ({ ...prev, [activeIndex]: [] }));
      setIsSearchingByIndex((prev) => ({ ...prev, [activeIndex]: false }));
      return;
    }

    const controller = new AbortController();
    const timer = setTimeout(async () => {
      try {
        setIsSearchingByIndex((prev) => ({ ...prev, [activeIndex]: true }));
        const res = await fetch(`/api/banks/search?q=${encodeURIComponent(keyword)}&limit=8`, {
          signal: controller.signal,
        });
        const json = await res.json();
        const items = Array.isArray(json.items) ? json.items : [];
        setSuggestionsByIndex((prev) => ({ ...prev, [activeIndex]: items }));
        setHighlightedByIndex((prev) => ({ ...prev, [activeIndex]: items.length > 0 ? 0 : -1 }));
      } catch (error) {
        if (error.name !== 'AbortError') {
          setSuggestionsByIndex((prev) => ({ ...prev, [activeIndex]: [] }));
          setHighlightedByIndex((prev) => ({ ...prev, [activeIndex]: -1 }));
        }
      } finally {
        setIsSearchingByIndex((prev) => ({ ...prev, [activeIndex]: false }));
      }
    }, 220);

    return () => {
      clearTimeout(timer);
      controller.abort();
    };
  }, [isOpen, activeIndex, assets]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 flex items-center justify-center bg-slate-900/40 p-4 backdrop-blur-xs z-50">
      <div className="w-full max-w-2xl overflow-hidden rounded-2xl border border-rose-100 bg-white shadow-xl flex flex-col max-h-[90vh]">
        <div className="flex items-center justify-between border-b border-rose-100 px-6 py-4 shrink-0">
          <h3 className="flex items-center gap-2 text-sm font-bold text-slate-900">
            ✎ 管理活存與負債餘額
          </h3>
          <button onClick={onClose} className="text-slate-400 transition hover:text-slate-600">
            ✕
          </button>
        </div>

        <div className="p-6 overflow-y-auto space-y-4 flex-1">
          <p className="text-xs text-slate-400">
            您可以在此手動輸入或更新各大銀行、信託、借貸 or 信用卡的名稱與目前金額。更新後點選「全部儲存」將即時同步至 Google Sheets。
          </p>

          <div className="space-y-4">
            {assets.map((item, index) => (
              <div key={item.id} className="flex items-center gap-3 rounded-xl border border-slate-200/60 bg-slate-50 p-3.5">
                <div className="w-1/3">
                  <label className="mb-0.5 block text-[10px] font-bold uppercase text-slate-400">分類</label>
                  <select
                    value={item.category}
                    onChange={(e) => onUpdate(index, { ...item, category: e.target.value, isLiability: e.target.value === '負債項目' })}
                    className="w-full rounded-lg border border-slate-200 bg-white p-1.5 text-xs text-slate-800"
                  >
                    <option value="台幣活存">台幣活存</option>
                    <option value="外幣活存">外幣活存</option>
                    <option value="員工持股信託">員工持股信託</option>
                    <option value="負債項目">負債項目</option>
                  </select>
                </div>
                <div className="w-1/3">
                  <label className="mb-0.5 block text-[10px] font-bold uppercase text-slate-400">名稱</label>
                  <div className="relative">
                    <input
                      type="text"
                      value={item.name}
                      onChange={(e) => {
                        onUpdate(index, { ...item, name: e.target.value });
                        setActiveIndex(index);
                        setHighlightedByIndex((prev) => ({ ...prev, [index]: 0 }));
                      }}
                      onKeyDown={(e) => handleNameKeyDown(e, index)}
                      onFocus={() => {
                        setActiveIndex(index);
                        if ((suggestionsByIndex[index] || []).length > 0) {
                          setHighlightedByIndex((prev) => ({ ...prev, [index]: 0 }));
                        }
                      }}
                      onBlur={() => {
                        setTimeout(() => {
                          setActiveIndex((prev) => (prev === index ? null : prev));
                          setHighlightedByIndex((prev) => ({ ...prev, [index]: -1 }));
                        }, 120);
                      }}
                      placeholder="例如：台新、國泰、玉山"
                      className="w-full rounded-lg border border-slate-200 bg-white p-1.5 text-xs text-slate-800"
                    />
                    {activeIndex === index && ((suggestionsByIndex[index] || []).length > 0 || isSearchingByIndex[index]) && (
                      <div className="absolute z-20 mt-1 max-h-48 w-full overflow-auto rounded-lg border border-slate-200 bg-white shadow-lg">
                        {isSearchingByIndex[index] && (
                          <div className="px-2 py-1.5 text-[11px] text-slate-400">搜尋中...</div>
                        )}
                        {!isSearchingByIndex[index] &&
                          (suggestionsByIndex[index] || []).map((name, suggestionIndex) => (
                            <button
                              key={name}
                              type="button"
                              onMouseDown={(e) => e.preventDefault()}
                              onMouseEnter={() => setHighlightedByIndex((prev) => ({ ...prev, [index]: suggestionIndex }))}
                              onClick={() => pickSuggestion(index, name)}
                              className={`block w-full px-2 py-1.5 text-left text-[11px] text-slate-700 transition ${
                                (highlightedByIndex[index] ?? -1) === suggestionIndex
                                  ? 'bg-rose-50'
                                  : 'hover:bg-rose-50'
                              }`}
                            >
                              {name}
                            </button>
                          ))}
                      </div>
                    )}
                  </div>
                </div>
                <div className="w-1/4">
                  <label className="mb-0.5 block text-[10px] font-bold uppercase text-slate-400">金額 (TWD)</label>
                  <input
                    type="number"
                    value={item.balance}
                    onChange={(e) => onUpdate(index, { ...item, balance: Number(e.target.value) || 0 })}
                    className="w-full rounded-lg border border-slate-200 bg-white p-1.5 text-right font-mono text-xs text-slate-800"
                  />
                </div>
                <div className="pt-4">
                  <button
                    onClick={() => onRemove(index)}
                    className="rounded-lg p-1.5 text-slate-400 transition hover:text-rose-500"
                    title="移除本項"
                  >
                    ✕
                  </button>
                </div>
              </div>
            ))}
          </div>

          <button
            onClick={onAddNew}
            className="w-full flex items-center justify-center gap-1 rounded-xl border border-dashed border-slate-300 bg-slate-50 py-2 text-xs font-bold text-slate-500 transition hover:bg-slate-100"
          >
            ➕ 新增一個帳戶/負債項目
          </button>
        </div>

        <div className="border-t border-rose-50 bg-slate-50 px-6 py-4 flex gap-3 shrink-0">
          <button
            type="button"
            onClick={onClose}
            className="w-1/2 rounded-lg border border-slate-200 bg-white py-2.5 text-sm font-semibold text-slate-600 transition hover:bg-slate-100"
          >
            關閉
          </button>
          <button
            type="button"
            onClick={onSave}
            className="w-1/2 rounded-lg bg-rose-500 py-2.5 text-sm font-semibold text-white shadow-md shadow-rose-100 transition hover:bg-rose-600"
          >
            全部儲存同步 
          </button>
        </div>
      </div>
    </div>
  );
}

export function CustomDialog({ isOpen, onClose, title, message, buttons = [] }) {
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 flex items-center justify-center bg-slate-900/40 p-4 backdrop-blur-xs z-50">
      <div className="w-full max-w-md overflow-hidden rounded-2xl border border-slate-200 bg-white p-6 shadow-xl">
        <div className="flex items-start gap-3">
          <div className="rounded-xl bg-rose-50 p-2 text-rose-600">
            ℹ️
          </div>
          <div>
            <h3 className="text-sm font-bold text-slate-900">{title}</h3>
            <p className="mt-1.5 whitespace-pre-line text-xs leading-relaxed text-slate-500" style={{ wordBreak: 'break-all' }}>
              {message}
            </p>
          </div>
        </div>
        <div className="flex justify-end gap-3 pt-4">
          {buttons.map((btn, idx) => (
            <button
              key={idx}
              onClick={btn.onClick}
              className={`rounded-xl px-4 py-2 text-xs font-bold transition ${
                btn.isPrimary
                  ? 'bg-rose-500 text-white shadow-sm shadow-rose-100 hover:bg-rose-600'
                  : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
              }`}
            >
              {btn.label}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';

export function TransactionModal({ isOpen, onClose, onSubmit }) {
  const [market, setMarket] = useState('TWSE');
  const [type, setType] = useState('buy');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [stock, setStock] = useState('');
  const [qty, setQty] = useState('');
  const [price, setPrice] = useState('');
  const [note, setNote] = useState('');
  const [isPriceManual, setIsPriceManual] = useState(false);
  const [selectedSymbol, setSelectedSymbol] = useState('');
  const [suggestions, setSuggestions] = useState([]);
  const [isSearching, setIsSearching] = useState(false);
  const [showSuggestions, setShowSuggestions] = useState(false);

  const rawTotal = Number(qty) * Number(price) || 0;
  let fee = 0;
  let finalTotal = rawTotal;

  if (type === 'buy') {
    fee = Math.max(20, Math.floor(rawTotal * 0.001425));
    finalTotal = rawTotal + fee;
  } else if (type === 'sell') {
    fee = Math.max(20, Math.floor(rawTotal * 0.001425)) + Math.floor(rawTotal * 0.003);
    finalTotal = rawTotal - fee;
  }

  const handleSubmit = (e) => {
    e.preventDefault();
    onSubmit({
      type,
      date,
      stock,
      qty: Number(qty),
      price: Number(price),
      note,
      rawTotal,
      actualAmount: finalTotal,
      market,
      symbol: selectedSymbol,
    });
    setStock('');
    setQty('');
    setPrice('');
    setNote('');
    setSelectedSymbol('');
    setIsPriceManual(false);
    setSuggestions([]);
    setShowSuggestions(false);
  };

  useEffect(() => {
    if (!isOpen) return;

    const keyword = stock.trim();
    if (!keyword) {
      setSuggestions([]);
      setIsSearching(false);
      return;
    }

    const controller = new AbortController();
    const timer = setTimeout(async () => {
      try {
        setIsSearching(true);
        const res = await fetch(`/api/stocks/search?q=${encodeURIComponent(keyword)}&market=${market}&limit=8`, {
          signal: controller.signal,
        });
        const json = await res.json();
        setSuggestions(Array.isArray(json.items) ? json.items : []);
      } catch (error) {
        if (error.name !== 'AbortError') {
          setSuggestions([]);
        }
      } finally {
        setIsSearching(false);
      }
    }, 220);

    return () => {
      clearTimeout(timer);
      controller.abort();
    };
  }, [stock, isOpen, market]);

  const handleSelectSuggestion = async (item) => {
    const nextStockText = item.display;
    const isDifferentStock = !!selectedSymbol && selectedSymbol !== item.symbol;
    const shouldKeepManualPrice = isPriceManual && !isDifferentStock;

    setStock(nextStockText);
    setSelectedSymbol(item.symbol);
    setShowSuggestions(false);

    if (shouldKeepManualPrice) {
      return;
    }

    let nextPrice = null;
    try {
      const quoteRes = await fetch(
        `/api/stocks/quote?symbol=${encodeURIComponent(item.symbol)}&market=${market}`
      );
      const quoteJson = await quoteRes.json();
      if (quoteJson && quoteJson.price !== null && quoteJson.price !== undefined) {
        nextPrice = quoteJson.price;
      }
    } catch (error) {
      // Ignore network failure and fallback to search payload price.
    }

    if ((nextPrice === null || nextPrice === undefined) && item.closePrice !== null && item.closePrice !== undefined) {
      nextPrice = item.closePrice;
    }

    if (nextPrice !== null && nextPrice !== undefined) {
      setPrice(String(nextPrice));
      setIsPriceManual(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 flex items-center justify-center bg-slate-900/40 p-4 backdrop-blur-xs z-50">
      <div className="w-full max-w-lg overflow-hidden rounded-2xl border border-rose-100 bg-white shadow-xl">
        <div className="flex items-center justify-between border-b border-rose-100 px-6 py-4">
          <h3 className="flex items-center gap-2 text-sm font-bold text-slate-900">
            ➕ 記錄股票交易
          </h3>
          <button onClick={onClose} className="text-slate-400 transition hover:text-slate-600">
            ✕
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4 p-6">
          <div>
            <label className="mb-2 block text-xs font-semibold text-slate-500">選擇交易類型</label>
            <div className="grid grid-cols-2 gap-3">
              <button
                type="button"
                onClick={() => setType('buy')}
                className={`rounded-xl border-2 py-3 px-4 text-center text-sm font-bold flex items-center justify-center gap-2 transition ${
                  type === 'buy'
                    ? 'border-rose-500 bg-rose-50/50 text-rose-700 shadow-sm shadow-rose-100'
                    : 'border-slate-200 text-slate-600 hover:bg-slate-50'
                }`}
              >
                <span className="h-2.5 w-2.5 animate-pulse rounded-full bg-rose-600"></span>
                買進 (Buy)
              </button>
              <button
                type="button"
                onClick={() => setType('sell')}
                className={`rounded-xl border-2 py-3 px-4 text-center text-sm font-bold flex items-center justify-center gap-2 transition ${
                  type === 'sell'
                    ? 'border-emerald-500 bg-emerald-50/50 text-emerald-700 shadow-sm shadow-emerald-100'
                    : 'border-slate-200 text-slate-600 hover:bg-slate-50'
                }`}
              >
                <span className="h-2.5 w-2.5 animate-pulse rounded-full bg-emerald-600"></span>
                賣出 (Sell)
              </button>
            </div>
          </div>

          <div className="grid grid-cols-3 gap-4">
            <div>
              <label className="mb-1 block text-xs font-semibold text-slate-500">市場</label>
              <select
                value={market}
                onChange={(e) => {
                  const nextMarket = e.target.value;
                  setMarket(nextMarket);
                  setStock('');
                  setSelectedSymbol('');
                  setSuggestions([]);
                  setShowSuggestions(false);
                  // 切換市場時不重置手動輸入狀態，等待選股規則判斷。
                }}
                className="w-full rounded-lg border border-slate-200 bg-slate-50 px-3 py-2 text-sm text-slate-800 transition focus:border-rose-300 focus:bg-white focus:outline-none"
              >
                <option value="TWSE">台股</option>
                <option value="US">美股</option>
              </select>
            </div>
            <div>
              <label className="mb-1 block text-xs font-semibold text-slate-500">交易日期</label>
              <input
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full rounded-lg border border-slate-200 bg-slate-50 px-3 py-2 text-sm text-slate-800 transition focus:border-rose-300 focus:bg-white focus:outline-none"
              />
            </div>
            <div className="relative col-span-3 md:col-span-1">
              <label className="mb-1 block text-xs font-semibold text-slate-500">股票名稱或代碼</label>
              <input
                type="text"
                value={stock}
                onChange={(e) => {
                  setStock(e.target.value);
                  setSelectedSymbol('');
                  setShowSuggestions(true);
                }}
                onFocus={() => setShowSuggestions(true)}
                onBlur={() => {
                  // Delay closing so click events on suggestion items can fire first.
                  setTimeout(() => setShowSuggestions(false), 120);
                }}
                placeholder="2330 台積電"
                className="w-full rounded-lg border border-slate-200 bg-slate-50 px-3 py-2 text-sm text-slate-800 transition focus:border-rose-300 focus:bg-white focus:outline-none"
                required
              />
              {showSuggestions && (stock.trim() || isSearching) && (
                <div className="absolute z-20 mt-1 max-h-56 w-full overflow-auto rounded-lg border border-slate-200 bg-white shadow-lg">
                  {isSearching && (
                    <div className="px-3 py-2 text-xs text-slate-400">搜尋中...</div>
                  )}
                  {!isSearching && suggestions.length === 0 && (
                    <div className="px-3 py-2 text-xs text-slate-400">找不到符合的股票</div>
                  )}
                  {!isSearching &&
                    suggestions.map((item) => (
                      <button
                        key={`${item.market}_${item.symbol}`}
                        type="button"
                        onMouseDown={(e) => e.preventDefault()}
                        onClick={() => handleSelectSuggestion(item)}
                        className="flex w-full items-center justify-between px-3 py-2 text-left text-xs transition hover:bg-rose-50"
                      >
                        <span className="font-semibold text-slate-700">{item.symbol} {item.name}</span>
                        <span className="text-slate-400">
                          {item.market}
                          {item.closePrice !== null && item.closePrice !== undefined
                            ? ` · ${item.closePrice}`
                            : ''}
                        </span>
                      </button>
                    ))}
                </div>
              )}
              <p className="mt-1 text-[11px] text-slate-400">
                {market === 'TWSE'
                  ? '台股可輸入代碼或名稱，例如「2330」或「台積電」。'
                  : '美股可輸入代碼或名稱，例如「AAPL」或「Apple」。'}
              </p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="mb-1 block text-xs font-semibold text-slate-500">交易股數</label>
              <input
                type="number"
                value={qty}
                onChange={(e) => setQty(e.target.value)}
                className="w-full rounded-lg border border-slate-200 bg-slate-50 px-3 py-2 text-sm text-slate-800 transition focus:border-rose-300 focus:bg-white focus:outline-none"
                min="1"
                required
              />
            </div>
            <div>
              <label className="mb-1 block text-xs font-semibold text-slate-500">每股單價</label>
              <input
                type="number"
                value={price}
                onChange={(e) => {
                  setPrice(e.target.value);
                  setIsPriceManual(true);
                }}
                className="w-full rounded-lg border border-slate-200 bg-slate-50 px-3 py-2 text-sm text-slate-800 transition focus:border-rose-300 focus:bg-white focus:outline-none"
                step="0.01"
                min="0.01"
                required
              />
            </div>
          </div>

          <div className="space-y-1.5 rounded-xl border border-slate-100 bg-slate-50 p-3.5 text-xs">
            <div className="flex justify-between">
              <span className="text-slate-500">成交原始總額：</span>
              <span className="font-mono font-medium text-slate-800">${rawTotal.toLocaleString()}</span>
            </div>
            {type !== 'dividend' && (
              <div className="flex justify-between text-[11px]">
                <span className="text-slate-500">手續費估算：</span>
                <span className="font-mono text-slate-600">${fee.toLocaleString()}</span>
              </div>
            )}
            <div className="border-t border-slate-200 pt-2 mt-1 flex justify-between font-bold">
              <span className="text-slate-700">{type === 'buy' ? '實際支出：' : '實際收入：'}</span>
              <span className="font-mono text-sm text-rose-600">${finalTotal.toLocaleString()}</span>
            </div>
          </div>

          <div>
            <label className="mb-1 block text-xs font-semibold text-slate-500">備註原因</label>
            <textarea
              value={note}
              onChange={(e) => setNote(e.target.value)}
              placeholder="例如：定期定額、看好財報..."
              rows="2"
              className="w-full resize-none rounded-lg border border-slate-200 bg-slate-50 px-3 py-2 text-sm text-slate-800 transition focus:border-rose-300 focus:bg-white focus:outline-none"
            />
          </div>

          <div className="flex gap-3 pt-2">
            <button
              type="button"
              onClick={onClose}
              className="w-1/2 rounded-lg bg-slate-100 py-2.5 text-sm font-semibold text-slate-600 transition hover:bg-slate-200"
            >
              取消
            </button>
            <button
              type="submit"
              className="w-1/2 rounded-lg bg-rose-500 py-2.5 text-sm font-semibold text-white shadow-md shadow-rose-100 transition hover:bg-rose-600"
            >
              確定存檔
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export function ConfigModal({ isOpen, onClose, onConnect }) {
  const [apiUrl, setApiUrl] = useState('');

  const handleConnect = () => {
    if (apiUrl.trim()) {
      onConnect(apiUrl);
      setApiUrl('');
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 flex items-center justify-center bg-slate-900/40 p-4 backdrop-blur-xs z-50">
      <div className="w-full max-w-2xl overflow-hidden rounded-2xl border border-slate-200 bg-white shadow-xl">
        <div className="flex items-center justify-between border-b border-rose-100 px-6 py-4">
          <h3 className="flex items-center gap-2 text-sm font-bold text-slate-900">
            ☁️ 設置 Google 試算表同步後端
          </h3>
          <button onClick={onClose} className="text-slate-400 transition hover:text-slate-600">
            ✕
          </button>
        </div>

        <div className="space-y-4 overflow-y-auto p-6 max-h-[80vh]">
          <div className="space-y-2 rounded-xl border border-rose-100 bg-rose-50/50 p-4 text-xs leading-relaxed text-slate-700">
            <p className="text-sm font-bold text-rose-950"> 升級版 Google Apps Script 二分鐘極速架設法：</p>
            <ol className="list-inside list-decimal space-y-1.5 text-slate-600">
              <li>打開您的 Google 試算表。</li>
              <li>點選上方選單的 「擴充功能」 -&gt; 「Apps Script」。</li>
              <li>清除所有舊代碼，貼入後端代碼。</li>
              <li>點擊 「儲存」，再點右上角 「部署」 -&gt; 「新增部署版本」。</li>
              <li>複製產生的「網頁應用程式 URL」貼在下方！</li>
            </ol>
          </div>

          <div>
            <label className="mb-1.5 block text-xs font-bold text-slate-700">網頁應用程式 URL (Web App URL)</label>
            <input
              type="text"
              value={apiUrl}
              onChange={(e) => setApiUrl(e.target.value)}
              placeholder="https://script.google.com/macros/s/.../exec"
              className="w-full rounded-lg border border-slate-200 bg-slate-50 px-3 py-2.5 text-xs text-slate-800 transition focus:border-rose-300 focus:bg-white focus:outline-none"
            />
          </div>

          <div className="flex gap-3 pt-2">
            <button
              type="button"
              onClick={onClose}
              className="w-1/2 rounded-lg bg-slate-100 py-2.5 text-sm font-semibold text-slate-600 transition hover:bg-slate-200"
            >
              關閉
            </button>
            <button
              type="button"
              onClick={handleConnect}
              className="w-1/2 flex items-center justify-center gap-1.5 rounded-lg bg-rose-500 py-2.5 text-sm font-semibold text-white shadow-md shadow-rose-100 transition hover:bg-rose-600"
            >
               直接儲存連線
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

export function Toast({ message, isVisible }) {
