}

'use client';

import { useEffect, useRef, useState } from 'react';
import { useApp } from '@/lib/app-context';

// ─── helpers ─────────────────────────────────────────────────────────────────

function buildBasePositions(txList) {
  const map = {};
  const sorted = [...txList].sort((a, b) => new Date(a.date) - new Date(b.date));

  sorted.forEach((tx) => {
    const key = tx.stock;
    if (!map[key]) {
      map[key] = {
        name: tx.stock,
        symbol: tx.symbol || tx.stock.split(' ')[0],
        market: tx.market || 'TWSE',
        holdingQty: 0,
        totalBuyCost: 0,
      };
    }
    const pos = map[key];
    if (tx.type === 'buy') {
      pos.holdingQty += Number(tx.qty);
      pos.totalBuyCost += Number(tx.actualAmount);
    } else if (tx.type === 'sell' && pos.holdingQty > 0) {
      const sold = Math.min(Number(tx.qty), pos.holdingQty);
      const ratio = sold / pos.holdingQty;
      pos.holdingQty -= sold;
      pos.totalBuyCost *= 1 - ratio;
    }
  });

  return Object.values(map)
    .filter((p) => p.holdingQty > 0)
    .map((p) => ({
      ...p,
      avgCost: p.holdingQty > 0 ? p.totalBuyCost / p.holdingQty : 0,
    }));
}

function tabBtnClass(active) {
  return `px-3 py-1.5 rounded-lg text-xs font-bold transition ${
    active ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-500 hover:text-slate-700'
  }`;
}

function fmt(num) {
  return Math.round(num).toLocaleString('zh-TW');
}

// "2026-03-02" → "2026/3/2"
function fmtDate(dateStr) {
  if (!dateStr) return '';
  const [y, m, d] = dateStr.split('-');
  return `${y}/${parseInt(m)}/${parseInt(d)}`;
}

// ISO string → "13:02"（local time, 24h）
function fmtTime(isoStr) {
  if (!isoStr) return null;
  const d = new Date(isoStr);
  return `${d.getHours().toString().padStart(2, '0')}:${d.getMinutes().toString().padStart(2, '0')}`;
}

// ─── component ────────────────────────────────────────────────────────────────

export function StocksContent({ initialPrices = {} }) {
  const { transactions, removeTransaction } = useApp();

  const [priceMap, setPriceMap] = useState(initialPrices);
  const [isFetchingPrices, setIsFetchingPrices] = useState(false);
  const [posTab, setPosTab] = useState('TWSE');
  const [histTab, setHistTab] = useState('TWSE');
  const fetchedRef = useRef(new Set());

  // ── derive positions ──────────────────────────────────────────────────────

  const basePositions = buildBasePositions(transactions);
  const positionKeys = basePositions.map((p) => p.name).join('|');

  const allPositions = basePositions.map((p) => {
    const marketPrice = priceMap[p.name] ?? 0;
    const marketValue = p.holdingQty * marketPrice;
    const unrealizedProfit = marketValue - p.totalBuyCost;
    const profitPercent =
      p.totalBuyCost > 0 ? (unrealizedProfit / p.totalBuyCost) * 100 : 0;
    return { ...p, marketPrice, marketValue, unrealizedProfit, profitPercent };
  });

  const totalValue = allPositions.reduce((s, p) => s + p.marketValue, 0);
  const totalCost = allPositions.reduce((s, p) => s + p.totalBuyCost, 0);
  const totalUnrealized = totalValue - totalCost;

  const twsePositions = allPositions.filter((p) => p.market === 'TWSE');
  const usPositions = allPositions.filter((p) => p.market === 'US');
  const activePositions = posTab === 'TWSE' ? twsePositions : usPositions;

  // ── fetch live prices for new positions ───────────────────────────────────

  useEffect(() => {
    const toFetch = basePositions.filter((p) => !fetchedRef.current.has(p.name));
    if (toFetch.length === 0) return;

    setIsFetchingPrices(true);
    Promise.allSettled(
      toFetch.map((pos) =>
        fetch(
          `/api/stocks/quote?symbol=${encodeURIComponent(pos.symbol)}&market=${pos.market}`
        )
          .then((r) => r.json())
          .then((data) => ({ name: pos.name, price: data.price }))
      )
    ).then((results) => {
      const newPrices = {};
      results.forEach((r) => {
        if (r.status === 'fulfilled' && r.value.price != null) {
          newPrices[r.value.name] = r.value.price;
        }
      });
      toFetch.forEach((pos) => fetchedRef.current.add(pos.name));
      if (Object.keys(newPrices).length > 0) {
        setPriceMap((prev) => ({ ...prev, ...newPrices }));
      }
      setIsFetchingPrices(false);
    });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [positionKeys]);

  const handlePriceChange = (name, value) => {
    const num = parseFloat(value);
    setPriceMap((prev) => ({ ...prev, [name]: isNaN(num) ? 0 : num }));
  };

  // ── transaction history ───────────────────────────────────────────────────

  const twseTx = transactions.filter((tx) => (tx.market || 'TWSE') === 'TWSE');
  const usTx = transactions.filter((tx) => tx.market === 'US');
  const activeTx = [...(histTab === 'TWSE' ? twseTx : usTx)].sort(
    (a, b) => new Date(b.date) - new Date(a.date)
  );

  // ─────────────────────────────────────────────────────────────────────────

  return (
    <>
      {/* ── Summary Stats ── */}
      <div className="grid grid-cols-1 gap-4 md:grid-cols-3">
        <div className="card p-5">
          <p className="text-xs font-bold uppercase tracking-wide text-slate-400">持股現值總計</p>
          <p className="mt-2 text-2xl font-black text-slate-900">${fmt(totalValue)}</p>
        </div>
        <div className="card p-5">
          <p className="text-xs font-bold uppercase tracking-wide text-slate-400">總投資成本</p>
          <p className="mt-2 text-2xl font-black text-slate-900">${fmt(totalCost)}</p>
        </div>
        <div className="card p-5">
          <p className="text-xs font-bold uppercase tracking-wide text-slate-400">未實現損益</p>
          <p className={`mt-2 text-2xl font-black ${totalUnrealized >= 0 ? 'text-rose-600' : 'text-emerald-600'}`}>
            {totalUnrealized >= 0 ? '+' : '-'}${fmt(Math.abs(totalUnrealized))}
          </p>
        </div>
      </div>

      {/* ── Positions Section ── */}
      <div className="card overflow-hidden">
        <div className="flex items-center justify-between border-b border-slate-100 px-5 py-4">
          <div className="flex items-center gap-3">
            <h2 className="text-sm font-bold text-slate-800">個人即時持股明細</h2>
            {isFetchingPrices && (
              <span className="animate-pulse text-[11px] text-rose-400">⟳ 更新現價中…</span>
            )}
          </div>
          <div className="flex items-center gap-1 rounded-xl bg-slate-100 p-0.5">
            <button onClick={() => setPosTab('TWSE')} className={tabBtnClass(posTab === 'TWSE')}>
               台股
            </button>
            <button onClick={() => setPosTab('US')} className={tabBtnClass(posTab === 'US')}>
               美股
            </button>
          </div>
        </div>

        {activePositions.length === 0 ? (
          <div className="px-5 py-12 text-center text-sm text-slate-400">
            目前沒有 {posTab === 'TWSE' ? '台股' : '美股'} 持股紀錄
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full min-w-[960px] text-left">
              <thead className="bg-slate-50 text-[11px] font-bold uppercase tracking-wide text-slate-400">
                <tr>
                  <th className="px-4 py-3 align-middle">股票代號 / 名稱</th>
                  <th className="px-4 py-3 align-middle text-right">持有股數</th>
                  <th className="px-4 py-3 align-middle text-right">成本價</th>
                  <th className="px-4 py-3 align-middle text-right">現價</th>
                  <th className="px-4 py-3 align-middle text-right">投資成本</th>
                  <th className="px-4 py-3 align-middle text-right">帳面現值</th>
                  <th className="px-4 py-3 align-middle text-right">未實現損益</th>
                  <th className="px-4 py-3 align-middle text-right">損益率</th>
                  <th className="px-4 py-3 align-middle text-right">市值佔比</th>
                </tr>
              </thead>
              <tbody>
                {activePositions.map((pos) => {
                  const sharePercent =
                    totalValue > 0 ? (pos.marketValue / totalValue) * 100 : 0;
                  const nameParts = pos.name.split(' ');
                  const displayName = nameParts.slice(1).join(' ') || nameParts[0];

                  return (
                    <tr key={pos.name} className="border-t border-slate-100 hover:bg-slate-50/60 transition">
                      {/* 股票代號 / 名稱 */}
                      <td className="px-4 py-3 align-middle">
                        <div className="text-sm font-bold text-slate-400">{pos.symbol}</div>
                        <div className="text-sm text-slate-800">{displayName}</div>
                      </td>

                      {/* 持有股數 */}
                      <td className="px-4 py-3 align-middle text-right font-mono text-sm text-slate-700">
                        {pos.holdingQty.toLocaleString()}
                      </td>

                      {/* 成本價 */}
                      <td className="px-4 py-3 align-middle text-right font-mono text-sm text-slate-700">
                        {pos.avgCost.toFixed(2)}
                      </td>

                      {/* 現價 (editable) */}
                      <td className="px-4 py-3 align-middle text-right">
                        <input
                          type="number"
                          value={pos.marketPrice || ''}
                          onChange={(e) => handlePriceChange(pos.name, e.target.value)}
                          className="w-24 rounded-lg border border-slate-200 bg-white px-2 py-1 text-right font-mono text-sm text-slate-800 transition focus:border-rose-300 focus:outline-none"
                          step="0.01"
                          min="0"
                        />
                      </td>

                      {/* 投資成本 */}
                      <td className="px-4 py-3 align-middle text-right font-mono text-sm text-slate-700">
                        ${fmt(pos.totalBuyCost)}
                      </td>

                      {/* 帳面現值 */}
                      <td className="px-4 py-3 align-middle text-right font-mono text-sm text-slate-700">
                        ${fmt(pos.marketValue)}
                      </td>

                      {/* 未實現損益 */}
                      <td className={`px-4 py-3 align-middle text-right font-mono text-sm font-bold ${pos.unrealizedProfit >= 0 ? 'text-rose-600' : 'text-emerald-600'}`}>
                        {pos.unrealizedProfit >= 0 ? '+' : '-'}${fmt(Math.abs(pos.unrealizedProfit))}
                      </td>

                      {/* 損益率 */}
                      <td className={`px-4 py-3 align-middle text-right font-mono text-sm font-bold ${pos.profitPercent >= 0 ? 'text-rose-600' : 'text-emerald-600'}`}>
                        {pos.profitPercent >= 0 ? '+' : ''}{pos.profitPercent.toFixed(2)}%
                      </td>

                      {/* 市值佔比 + bar */}
                      <td className="px-4 py-3 align-middle">
                        <div className="flex items-center justify-end gap-2">
                          <span className="w-10 text-right font-mono text-xs text-slate-600">
                            {sharePercent.toFixed(1)}%
                          </span>
                          <div className="relative h-1.5 w-16 overflow-hidden rounded-full bg-slate-200">
                            <div
                              className="absolute left-0 top-0 h-full rounded-full bg-rose-400 transition-all duration-300"
                              style={{ width: `${Math.min(sharePercent, 100)}%` }}
                            />
                          </div>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* ── Transaction History ── */}
      <div className="card overflow-hidden">
        <div className="flex items-center justify-between border-b border-slate-100 px-5 py-4">
          <h2 className="text-sm font-bold text-slate-800">股票交易歷史紀錄</h2>
          <div className="flex items-center gap-1 rounded-xl bg-slate-100 p-0.5">
            <button onClick={() => setHistTab('TWSE')} className={tabBtnClass(histTab === 'TWSE')}>
               台股
            </button>
            <button onClick={() => setHistTab('US')} className={tabBtnClass(histTab === 'US')}>
               美股
            </button>
          </div>
        </div>

        {activeTx.length === 0 ? (
          <div className="px-5 py-12 text-center text-sm text-slate-400">
            目前沒有 {histTab === 'TWSE' ? '台股' : '美股'} 交易紀錄
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full min-w-[760px] text-left">
              <thead className="bg-slate-50 text-[11px] font-bold uppercase tracking-wide text-slate-400">
                <tr>
                  <th className="px-4 py-3">日期</th>
                  <th className="px-4 py-3">股票</th>
                  <th className="px-4 py-3">類型</th>
                  <th className="px-4 py-3 text-right">股數</th>
                  <th className="px-4 py-3 text-right">成交單價</th>
                  <th className="px-4 py-3 text-right">實際收支</th>
                  <th className="px-4 py-3">備註</th>
                  <th className="px-4 py-3 text-center">操作</th>
                </tr>
              </thead>
              <tbody>
                {activeTx.map((tx) => (
                  <tr key={tx.id} className="border-t border-slate-100 hover:bg-slate-50/60 transition">
                    <td className="px-4 py-3 font-mono text-xs text-slate-500">{tx.date}</td>
                    <td className="px-4 py-3 text-sm font-semibold text-slate-800">{tx.stock}</td>
                    <td className="px-4 py-3">
                      <span
                        className={`inline-flex items-center rounded-full px-2.5 py-0.5 text-[11px] font-bold ${
                          tx.type === 'buy'
                            ? 'bg-rose-50 text-rose-600'
                            : 'bg-emerald-50 text-emerald-600'
                        }`}
                      >
                        {tx.type === 'buy' ? '買進' : '賣出'}
                      </span>
                    </td>
                    <td className="px-4 py-3 text-right font-mono text-sm text-slate-700">
                      {Number(tx.qty).toLocaleString()}
                    </td>
                    <td className="px-4 py-3 text-right font-mono text-sm text-slate-700">
                      ${Number(tx.price).toLocaleString()}
                    </td>
                    <td
                      className={`px-4 py-3 text-right font-mono text-sm font-bold ${
                        tx.type === 'buy' ? 'text-rose-600' : 'text-emerald-600'
                      }`}
                    >
                      {tx.type === 'buy' ? '-' : '+'}${Number(tx.actualAmount).toLocaleString()}
                    </td>
                    <td className="px-4 py-3 text-xs text-slate-500">{tx.note || '—'}</td>
                    <td className="px-4 py-3 text-center">
                      <button
                        onClick={() => removeTransaction(tx.id)}
                        className="rounded-lg p-1.5 text-slate-400 transition hover:bg-rose-50 hover:text-rose-500"
                        title="刪除此筆紀錄"
                      >
                        <svg viewBox="0 0 20 20" fill="currentColor" className="h-4 w-4">
                          <path
                            fillRule="evenodd"
                            d="M8.75 1A2.75 2.75 0 006 3.75v.443c-.795.077-1.584.176-2.365.298a.75.75 0 10.23 1.482l.149-.022.841 10.518A2.75 2.75 0 007.596 19h4.807a2.75 2.75 0 002.742-2.53l.841-10.52.149.023a.75.75 0 00.23-1.482A41.03 41.03 0 0014 4.193v-.443A2.75 2.75 0 0011.25 1h-2.5zM10 4c.84 0 1.673.025 2.5.075V3.75c0-.69-.56-1.25-1.25-1.25h-2.5c-.69 0-1.25.56-1.25 1.25v.325C8.327 4.025 9.16 4 10 4zM8.58 7.72a.75.75 0 00-1.5.06l.3 7.5a.75.75 0 101.5-.06l-.3-7.5zm4.34.06a.75.75 0 10-1.5-.06l-.3 7.5a.75.75 0 101.5.06l.3-7.5z"
                            clipRule="evenodd"
                          />
                        </svg>
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </>
  );
}

